var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"부활의 지팡이를 되찾았다고?","JPN":"復活の杖を取り戻した？","ENG":"The Staff of Resurrection has been recovered?","TWN":"找到復活之杖了？"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"예. 대신전에서 보낸 전령이 그렇게 전하더군요.","JPN":"はい。大神殿からの伝令がそう伝えてきました。","ENG":"Yes, the messenger from the Great Temple has reported as such.","TWN":"是，殿下，是大神殿派人傳來的消息。"},"stage":{"bg":"ROOM_03","slots":{"L":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L6_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"남쪽 신전의 신전장이 직접 도둑을 체포하고 부활의 지팡이를 되찾아 왔다고 합니다.","JPN":"南方の神殿の神殿長がじかに泥棒を逮捕し、復活の杖を取り戻してきたようです。","ENG":"They have also reported that the Head Priestess of the Southern Temple has personally arrested the thieves and recovered the Staff of Resurrection.","TWN":"據說是南方神殿的祭司長親手抓到小偷，將復活之杖找回來的。"},"stage":{"bg":"ROOM_03","slots":{"L":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"서쪽 신전의 성녀 후보는 아무런 얘기도 없던가?","JPN":"西方の神殿の聖女候補は何も話してなかったのか？","ENG":"Is there no word regarding the candidate for the Sainthood from the Western Temple?","TWN":"西方神殿的聖女候選人什麼話都沒說嗎？"},"stage":{"bg":"ROOM_03","slots":{"L":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"오늘 새벽에 기도를 드리러 신전 기사들과 함께 대신전을 나선 뒤 행방이 묘연하다 합니다.","JPN":"今日の明け方、祈りを捧げるために神殿の騎士と一緒に大神殿を出た後、行方が知れないそうです。","ENG":"She has been missing since this morning after she left the Great Temple with the temple knights to pray.","TWN":"今天凌晨和神殿騎士一起到大神殿祈禱後，便下落不明。"},"stage":{"bg":"ROOM_03","slots":{"L":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"호오. 유력한 후보의 실종과 함께 사건을 해결하다니…….","JPN":"ほお。有力候補の失踪とともに事件を解決したと……","ENG":"Oh, is that so? So she has been able to resolve the case while at the same time another prime candidate has gone missing...","TWN":"呵呵，事情解決的同時，有望當選的候選人卻失蹤嗎……"},"stage":{"bg":"ROOM_03","slots":{"L":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"참으로 공교로운 우연 아닌가, 알렌 경.","JPN":"なんという偶然だろうか。なあ？　アレン卿。","ENG":"Is this not such a convenient coincidence, Sir Allen?","TWN":"真是巧呢，你說是不是，艾倫卿？"},"stage":{"bg":"ROOM_03","slots":{"L":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"전하. 이번 일은 그리 쉽게 넘길 사안이 아닙니다.","JPN":"殿下。今回の事件はそう簡単に済まされる案件ではございません。","ENG":"Your Highness, this is an incredibly delicate issue.","TWN":"殿下，這件事不能就這樣輕易放過。"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"사제장의 행적이 매우 의심스럽습니다.","JPN":"神殿長の行動が怪しすぎます。","ENG":"The Head Priestess’ conduct is very suspicious.","TWN":"祭司長的形跡非常可疑，"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"출정식을 연기하고 철저하게 이 사건에 대해 조사하시는 것이……","JPN":"出征式を延期し、この事件について徹底的に調査なさった方が……","ENG":"I would advise delaying the ceremony of war and ordering a thorough investigation into this matter...","TWN":"是否將出征儀式延後，先徹查這件事……"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"아니. 출정식은 예정대로 진행한다.","JPN":"いや。出征式は予定どおり進める。","ENG":"No. The ceremony of war will proceed as planned.","TWN":"不，出征儀式如期舉行。"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"온 제국민이 오늘까지 마왕에 맞설 구원 기사단의 출정을 기다려 왔다.","JPN":"すべての帝国民が今日まで魔王に立ち向かう救世騎士団の出征を待ってきたんだ。","ENG":"The entire empire has been waiting to this day for the Knights of Redemption to march against the Demon Lord.","TWN":"全帝國的百姓，都在期待救贖騎士團可以出征對付魔王。"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"이제 와서 연기한들 불안만 키울 뿐이지.","JPN":"今更引き延ばしても不安が濃くなるだけだ。","ENG":"Delaying the ceremony now will only serve to increase their anxiety.","TWN":"現在說要延後只怕會引發百姓的不滿。"},"stage":{"bg":"ROOM_03","slots":{"L":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"전하, 하오나……","JPN":"ですが、殿下……","ENG":"However, Your Highness...","TWN":"可是殿下……"},"stage":{"bg":"ROOM_03","slots":{"L":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L22_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"알렌 경. 직언을 서슴지 않는 그대의 충성은 높게 평가하고 있다.","JPN":"アレン卿。ためらわず直言するそなたの忠心は高く評価する。","ENG":"Sir Allen. Your loyalty and willingness to be blunt are held in high regard.","TWN":"艾倫卿，我非常欣賞你的忠心和敢於諫言。"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"하지만 군주라면 어떤 난관도 정면으로 돌파할 수 있어야 하는 법.","JPN":"だが、君主たる者、いかなる困難も正面から乗り越えていかくてはならん。","ENG":"However, a monarch must be able to overcome any obstacle head-on.","TWN":"不過身為一國之君，必須能夠正面迎戰任何難關。"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"나를 이 정도 일에 흔들릴 정도로 어리석은 군주라 여겼다면 다시 생각할 기회를 주지.","JPN":"私がこの程度のことで揺さぶられるほど愚かな君主だと思ったのなら、考え直す機会を与えてやろう。","ENG":"If you had considered me a foolish king who is easily shaken merely by something like this, then I will give you a chance to reassess me.","TWN":"若你認為我是會因為這點小事就動搖的昏君，那我給你個機會，再重新考慮一下是否要效忠於我吧？"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};